mapper.update:
UPDATE order_t
SET status = 'FAILED'
WHERE order_id = #{orderId}

UPDATE order_t
   SET status        = 'CANCELLED',
       cancel_reason = #{cancelReason},
       cancel_memo   = #{cancelMemo},
       cancel_date   = NOW(),
       refund_amount = #{refundAmount},
       refund_rate   = #{refundRate}
 WHERE order_id = #{orderId}
   AND m_id     = #{mId}
   AND status   = 'PAID'
